sql:
SELECT total_housing_target
FROM housing_targets
WHERE doc_id = 1;

SELECT doc_name
FROM documents
WHERE status = 'Draft' AND total_housing_target > 3000;

external_knowledge:
- "adopted after 2000" refers to documents with adoption dates after January 1, 2000; 
- "total housing targets" refers to the sum of 'total_housing_target' in the 'housing_targets' table for each document; 
- "exceeding 5000" refers to total housing targets greater than 5000.
